<script setup lang="ts">

import { ref, computed, onMounted, onUnmounted, watch } from 'vue';
import { NGrid, NGridItem, NCard, NButton } from 'naive-ui';
import { useMarketStore } from '@/stores/market';
import { storeToRefs } from 'pinia';

const marketStore = useMarketStore();
const { publicApps, isLoading, hasMore, searchApps, isSearchLoading, hasSearchMore } = storeToRefs(marketStore);

const scrollBody = ref<HTMLElement | null>(null);

const handleScroll = (e: Event) => {
  const target = e.target as HTMLElement;
  if (target.scrollTop + target.clientHeight >= target.scrollHeight - 50) {
    if (searchText.value.trim()) {
      if (!isSearchLoading.value && hasSearchMore.value) {
        console.log('搜索滚动事件触发');
        marketStore.getMoreSearchApplications(searchText.value.trim());
      }
    } else {
      if (!isLoading.value && hasMore.value) {
        console.log('滚动事件触发');
        marketStore.getPublicApplications();
      }
    }
  }
};

// 搜索相关
const searchText = ref('');
let searchTimeout: NodeJS.Timeout;

watch(searchText, (newVal) => {
  clearTimeout(searchTimeout);
  if (newVal.trim()) {
    searchTimeout = setTimeout(() => {
      marketStore.searchApplications(newVal.trim());
    }, 300);
  }
});

const filteredTools = computed(() => {
  if (searchText.value.trim()) {
    return searchApps.value;
  }
  return publicApps.value;
});







const gridCols = ref(3);
function updateGridCols() {
  const w = window.innerWidth;
  if (w < 600) gridCols.value = 1;
  else if (w < 900) gridCols.value = 2;
  else if (w < 1200) gridCols.value = 3;
  else if (w < 1600) gridCols.value = 4;
  else gridCols.value = 5;
}
onMounted(() => {
  updateGridCols();
  window.addEventListener('resize', updateGridCols);
});
onUnmounted(() => {
  window.removeEventListener('resize', updateGridCols);
});












const emit = defineEmits<{
  'show-info-page': [applicationId: string, source: string]
}>()

function goToInformationPage(applicationId: string) {
  emit('show-info-page', applicationId, 'market')
}


</script>







